SELECT election_id
FROM election_results
ORDER BY election_type, election_date, name;

SELECT SUM(votes) AS total_votes
FROM election_results
WHERE election_id = 1;

SELECT name, votes
FROM election_results
ORDER BY votes DESC;

SELECT DISTINCT party
FROM candidates
ORDER BY party;

SELECT name, voter_turnout_percentage
FROM election_results
ORDER BY voter_turnout_percentage DESC;

SELECT votes, voter_turnout_percentage
FROM election_results
WHERE election_id = 1;
